def find_signals(text: str, limit: int = 20):
    lower = text.lower()
    found = []
    for signal in SUPPORT_CATALOG:
        if signal.vendor.lower() in lower or signal.category.lower() in lower:
            found.append(signal)
        if len(found) >= limit:
            break
    return found
